<?php
 namespace WPAICG\AutoGPT\Cron\Init; use WPAICG\aipkit_dashboard; if (!defined('ABSPATH')) { exit; } function check_module_status_logic(string $main_cron_hook): bool { $option_key_autogpt_active = 'aipkit_autogpt_module_was_active'; $module_settings = aipkit_dashboard::get_module_settings(); $is_autogpt_currently_active = !empty($module_settings['autogpt']); $was_autogpt_active = (bool) get_option($option_key_autogpt_active, false); if (!$is_autogpt_currently_active) { if ($was_autogpt_active && wp_next_scheduled($main_cron_hook)) { wp_clear_scheduled_hook($main_cron_hook); } update_option($option_key_autogpt_active, false, 'no'); return false; } if (!$was_autogpt_active) { update_option($option_key_autogpt_active, true, 'no'); } return true; } 